/**
 * FileオブジェクトをRGBA PNGに変換（最大maxPxにリサイズ）
 */
export function toRGBAPng(file: File, maxPx = 2048): Promise<Blob> {
  return new Promise((resolve) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      let w = img.naturalWidth;
      let h = img.naturalHeight;
      if (w > maxPx || h > maxPx) {
        if (w > h) {
          h = Math.round((h * maxPx) / w);
          w = maxPx;
        } else {
          w = Math.round((w * maxPx) / h);
          h = maxPx;
        }
      }
      const canvas = document.createElement('canvas');
      canvas.width = w;
      canvas.height = h;
      canvas.getContext('2d')!.drawImage(img, 0, 0, w, h);
      URL.revokeObjectURL(url);
      canvas.toBlob((blob) => resolve(blob!), 'image/png');
    };
    img.src = url;
  });
}

/**
 * canvasにNEONOIRロゴと@neonoir_jpウォーターマークを合成する
 */
export function applyLogoWatermark(
  imageBase64: string,
  handle = '@neonoir_jp'
): Promise<string> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      const ctx = canvas.getContext('2d')!;
      ctx.drawImage(img, 0, 0);

      const w = canvas.width;
      const h = canvas.height;

      // --- ロゴ (左下、幅38%) ---
      const logoW = Math.round(w * 0.38);
      const logoH = Math.round((logoW * 745.9) / 1741.6);
      const logoX = Math.round(w * 0.02);
      const logoY = h - logoH - Math.round(h * 0.02);

      const svgBlob = new Blob([NEONOIR_SVG], { type: 'image/svg+xml' });
      const svgUrl = URL.createObjectURL(svgBlob);
      const logoImg = new Image();
      logoImg.onload = () => {
        // 黒アウトライン (4方向 drop-shadow)
        const offsets = [
          [-3, -3], [3, -3], [-3, 3], [3, 3],
          [-4, 0], [4, 0], [0, -4], [0, 4],
        ];
        ctx.save();
        ctx.globalAlpha = 0.85;
        ctx.filter = 'brightness(0)'; // 黒にする
        for (const [dx, dy] of offsets) {
          ctx.drawImage(logoImg, logoX + dx, logoY + dy, logoW, logoH);
        }
        ctx.filter = 'none';
        // ロゴ本体（白）
        ctx.globalAlpha = 0.92;
        ctx.drawImage(logoImg, logoX, logoY, logoW, logoH);
        ctx.restore();

        URL.revokeObjectURL(svgUrl);

        // --- SNSハンドル (右下) ---
        const fontSize = Math.round(w * 0.018);
        ctx.save();
        ctx.font = `700 ${fontSize}px Inter, sans-serif`;
        ctx.textAlign = 'right';
        ctx.textBaseline = 'bottom';
        ctx.shadowColor = 'rgba(0,0,0,0.9)';
        ctx.shadowBlur = 8;
        ctx.shadowOffsetX = 2;
        ctx.shadowOffsetY = 2;
        ctx.fillStyle = 'rgba(255,255,255,0.9)';
        const tx = w - Math.round(w * 0.02);
        const ty = h - Math.round(h * 0.015);
        ctx.fillText(handle, tx, ty);
        ctx.restore();

        resolve(canvas.toDataURL('image/png'));
      };
      logoImg.src = svgUrl;
    };
    img.src = `data:image/png;base64,${imageBase64}`;
  });
}
